public class Program8_ArithmeticOperator {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		// TODO Auto-generated method stub
    int num1=10 , num2=20;
    System.out.println(num1+num2);
    System.out.println(num2-num1);
    System.out.println(num1*num2);
    System.out.println(num1/num2);
    System.out.println(num1%num2);
    
	}

}
